// Express API in 10 lines
const app = require('express')();
app.use(require('express').json());
app.get('/', (_, r) => r.json({status: 'geil'}));
app.post('/data', (q, r) => r.json({got: q.body}));
app.listen(8000, () => console.log('Läuft auf 8000'));

// Rust Webserver der läuft
use warp::Filter;
#[tokio::main]
async fn main() {
    let route = warp::any().map(|| "CROD läuft!");
    warp::serve(route).run(([127, 0, 0, 1], 8000)).await;
}

